{
  "experiment_plan": {
    "what_to_compare": "2000–2010年の米国州×四半期パネルで、Castle Doctrine法（Stand Your Ground法）を採用した州の採用前後の変化を、同時期に未採用の州および未採用期間と比較する。主要比較は、採用州のイベント時点を基準にしたイベントスタディと、採用タイミングの異なる州間比較である。アウトカムは、殺人・過失致死、暴力犯罪全般、強盗、加重暴行、ならびに測定検証用に死亡統計・救急/医療記録ベースの致死的暴力指標を比較する。",
    "what_to_measure": "州×四半期の犯罪率（殺人・過失致死、暴力犯罪全般、強盗、加重暴行）、採用前後の動学的係数、州固定効果・時点固定効果を含む推定値、事前トレンドの有無、警察統計と外部データ（死亡統計、医療記録）の乖離、採用後の短期・中期・長期の効果パターンを測定する。",
    "procedure": "1) 州ごとのCastle Doctrine法採用時点を整理し、四半期単位のパネルを作成する。2) 主要分析として、採用イベントを基準にしたイベントスタディを実施し、採用前の係数で平行トレンドを検証する。3) 採用後の短期（0–4四半期）、中期（5–12四半期）、長期（13四半期以降）の係数を推定する。4) 暴力犯罪全般と殺人・過失致死、強盗、加重暴行を別々に推定し、実体効果の広がりを確認する。5) 測定メカニズム検証として、警察統計と死亡統計・医療記録の変化を比較する。6) 分析分岐として、TWFE DiD、Sun-Abraham型の異質処置効果に頑健な推定、採用州のみのイベントスタディ、外部データを用いた検証を並行実施する。",
    "identification_assumptions": [
      {
        "id": "IA1",
        "description": "採用前に、採用州と未採用州のアウトカムトレンドが条件付きで平行であること。",
        "if_violated": "採用前から系統的な差異トレンドがある場合、採用効果と既存トレンドを識別できず、DiD推定は因果解釈を失う。"
      },
      {
        "id": "IA2",
        "description": "Castle Doctrine法の採用時点が、州の犯罪動向に対する予期されたショックや同時期の主要政策変更と完全には共線でないこと。",
        "if_violated": "採用と同時に他の治安政策や景気ショックが集中すると、推定効果が法改正以外の要因を混同する。"
      },
      {
        "id": "IA3",
        "description": "採用州の採用タイミングが、未観測の短期的犯罪ショックに対する直接反応ではないこと。",
        "if_violated": "犯罪増加や減少への反応として法が導入されている場合、逆因果により推定が歪む。"
      },
      {
        "id": "IA4",
        "description": "州境をまたぐ犯罪の大規模な置換や測定制度変更が、主要アウトカムの比較を支配しないこと。",
        "if_violated": "犯罪の場所移動や統計分類変更が大きいと、観測された変化が実体効果か測定効果か判別できない。"
      },
      {
        "id": "IA5",
        "description": "外部検証に用いる死亡統計・医療記録が、警察統計とは独立に致死的暴力を測定していること。",
        "if_violated": "外部データも同じ報告バイアスを共有する場合、H4の識別力が低下する。"
      }
    ],
    "hypothesis_rules": [
      {
        "id": "H1",
        "accept_if": "採用後に、殺人・過失致死率と暴力犯罪全般がともに有意に低下し、少なくとも短期・中期の両方で同方向の負の係数が観察され、かつ採用前係数が概ねゼロで平行トレンドが支持される。",
        "reject_if": "採用後に、殺人・過失致死率が一貫して上昇する、または暴力犯罪全般の明確な減少が確認できない。",
        "hold_if": "殺人・過失致死は低下するが暴力犯罪全般の反応が不明確、または推定精度不足で短期・中期の方向が確定しない。"
      },
      {
        "id": "H2",
        "accept_if": "採用後に、殺人・過失致死率のみが有意に上昇し、強盗や加重暴行は同程度には上昇しない、または変化が弱いというパターンが短中期で確認される。",
        "reject_if": "採用後に、殺人・過失致死が増加しない、または少なくとも短中期で有意な上昇が確認できない。",
        "hold_if": "殺人・過失致死の上昇はあるが、強盗や加重暴行も同程度に増えるため、殺人特異的な増加と判定できない。"
      },
      {
        "id": "H3",
        "accept_if": "イベントスタディで、採用直後と数年後で係数の符号または大きさが明確に変化し、少なくとも一つのアウトカムで動学的反転または段階的変化が確認される。",
        "reject_if": "採用後の全期間を通じて効果の符号が一貫し、動学的な反転や段階的変化が見られない。",
        "hold_if": "採用後に時間変化はあるが、符号反転までは確認できない、または推定誤差が大きく動学的異質性を確定できない。"
      },
      {
        "id": "H4",
        "accept_if": "警察統計では変化が大きい一方で、死亡統計・医療記録ベースの致死的暴力では同方向の変化が弱いか不一致であり、特に殺人以外のカテゴリで乖離が大きい。",
        "reject_if": "警察統計だけでなく死亡統計・医療記録でも同方向かつ同程度の変化が確認され、測定・報告仮説より実体効果が支持される。",
        "hold_if": "警察統計と外部データの差が小さい、または外部データの精度不足で乖離の有無を判定できない。"
      }
    ],
    "analysis_forks": [
      "TWFE DiDによる基準推定と、異質処置効果に頑健なSun-Abraham型イベントスタディを併用する。",
      "採用州のみのイベントスタディで、採用前トレンドと採用後の短期・中期・長期効果を分解する。",
      "アウトカム別推定を分ける（殺人・過失致死、暴力犯罪全般、強盗、加重暴行）ことで、総合抑止と殺人特異的増加を識別する。",
      "警察統計と外部データ（死亡統計、医療記録）を比較し、実体効果と測定・報告効果を分岐する。",
      "州固定効果・時点固定効果に加え、州別線形トレンドや共変量調整を追加した頑健性分析を行う。",
      "採用時期の早い州と遅い州を分けて推定し、時間的異質性と負のウェイト問題の影響を点検する。"
    ]
  }
}
